const STALE_DAYS = 7;
const now = Date.now();

function daysSince(iso) {
  if (!iso) return Infinity;
  return Math.floor((now - new Date(iso).getTime()) / 86400000);
}

function lastActivity(eng) {
  const lastNote   = eng.notesLog?.slice(-1)[0]?.date;
  const lastOutput = eng.outputs?.slice(-1)[0]?.generatedAt;
  return [lastNote, lastOutput].filter(Boolean).sort().slice(-1)[0] ?? null;
}

const rows = $input.all();
const engagements = rows.flatMap(r => Array.isArray(r.json) ? r.json.map(row => row.data) : [r.json?.data].filter(Boolean));

const reminders = engagements
  .filter(eng => eng && eng.status === 'Active')
  .filter(eng => daysSince(lastActivity(eng)) >= STALE_DAYS)
  .map(eng => {
    const last      = lastActivity(eng);
    const days      = daysSince(last);
    const incomplete = (eng.workflow ?? []).filter(s => !s.done).map(s => s.label);
    const openRisks = (eng.risksLog ?? []).filter(r => r.status === 'Open');
    return {
      type:                        'stale-engagement',
      engagementId:                eng.id,
      clientName:                  eng.clientName,
      company:                     eng.company,
      serviceType:                 eng.serviceType,
      owner:                       eng.owner,
      daysSinceActivity:           days === Infinity ? null : days,
      lastActivityDate:            last ?? null,
      incompleteWorkflowStepCount: incomplete.length,
      openRisksCount:              openRisks.length,
      subject:                     `Reminder: ${eng.clientName} engagement needs attention`,
      message:                     `${eng.clientName} (${eng.company}): no activity for ${days} days. ${incomplete.length} incomplete step(s), ${openRisks.length} open risk(s).`
    };
  });

if (reminders.length === 0) return [{ json: { hasReminders: false, reminders: [] } }];

return [{
  json: {
    hasReminders:  true,
    count:         reminders.length,
    reminders,
    slackMessage:  `⚠️ *Barinhall stale engagement reminder*\n` + reminders.map(r => `• ${r.message}`).join('\n')
  }
}];
